import "../../index.css";
import logo from "../../../blocks/images/logo.svg";

function Header() {
  return (
    <>
      <header className="header page__section">
        <img
          alt="Logotipo Around The U.S."
          className="logo header__logo"
          src={logo}
        />
      </header>
    </>
  );
}

export default Header;
